UPDATE tb_article SET is_hot = true
WHERE id IN (
    SELECT id FROM (
        SELECT id FROM tb_article
        WHERE status = 1 AND is_deleted = false AND review = 'approved'
        ORDER BY (COALESCE(views, 0) + COALESCE(likes, 0) * 10 + COALESCE(comments, 0) * 5 + COALESCE(collections, 0) * 8) DESC
        LIMIT #{limit}
    ) t
)
